from math import gcd
from itertools import combinations
from functools import lru_cache

class Solution:
    def maxScore(self, nums: List[int]) -> int:
        @lru_cache(None)
        def dfs(mask, i):
            if i > len(nums) // 2:
                return 0
            res = 0
            for x, y in combinations(range(len(nums)), 2):
                if (mask & (1 << x)) and (mask & (1 << y)):
                    continue
                res = max(res, i * gcd(nums[x], nums[y]) + dfs(mask | (1 << x) | (1 << y), i + 1))
            return res
        return dfs(0, 1)
